 /**
  * Split an integer-cent total into `parts` as-equal-as-possible shares.
- * Stub — the coding agent implements this at eval time (task 001).
+ * Gives leftover cents to the earliest shares.
  */
 export function splitEvenly(total: number, parts: number): number[] {
-  throw new Error(`splitEvenly(${total}, ${parts}) not implemented`);
+  if (parts < 1) {
+    throw new Error("Number of parts must be at least 1.");
+  }
+
+  const baseShare = Math.floor(total / parts);
+  const remainder = total % parts;
+
+  const shares = Array(parts).fill(baseShare);
+
+  for (let i = 0; i < remainder; i++) {
+    shares[i]++;
+  }
+
+  return shares;
 }
